mapper.sql:
SELECT
    a.ID,
    a.STORAGE_CODE,
    a.STORAGE_NAME,
    a.STORAGE_TYPE_CODE,
    a.STORAGE_TYPE_NAME,
    a.ROW_COUNT,
    a.COLUMN_COUNT,
    a.STATUS,
    a.CREATE_BY,
    a.CREATE_TIME,
    a.UPDATE_BY,
    a.UPDATE_TIME,
    (select count(*) from M_STORAGE_STACK where STORAGE_CODE = a.STORAGE_CODE) CHILD_COUNT
FROM
M_STORAGE a



        and a.STORAGE_CODE LIKE #{storageCode}



        and a.STORAGE_NAME LIKE #{storageName}


        and a.STORAGE_TYPE_CODE = #{storageTypeCode}


        and a.STORAGE_TYPE_NAME = #{storageTypeName}


        and a.ROW_COUNT = #{rowCount}


        and a.COLUMN_COUNT = #{columnCount}


        and a.STATUS = #{status}
